// ============================================================
// v2.3 Backfill State Machine
// - Reads workflow static data for `lastBackfillAt`.
// - mode = 'backfill' on first run, 'daily' thereafter.
// - Computes NVD pubStart/pubEnd for daily path.
// ============================================================
$getWorkflowStaticData('global').lastBackfillAt = null;
const staticData = $getWorkflowStaticData('global');
const lastBackfillAt = staticData.lastBackfillAt ?? null;
const mode = lastBackfillAt ? 'daily' : 'backfill';

const now = new Date();
const yesterday = new Date(now.getTime() - 86400000).toISOString().split('T')[0];

return [{ json: {
  mode,
  lastBackfillAt,
  nowIso: now.toISOString(),
  nvdPubStart: yesterday + 'T00:00:00.000',
  nvdPubEnd: yesterday + 'T23:59:59.999',
  backfillDays: 365
}}];

// ============================================================
// v2.3 NVD/OpenCVE Crawler (backfill + daily unified)
// - Runs ALWAYS. Mode controls date windows:
//   · backfill → 4 × 120-day windows (NVD API range limit, 1y total)
//   · daily    → 1 window (yesterday)
// - NVD keyword is derived from D1 solutions' vendors (per-vendor query).
//   WHY: NVD keywordSearch uses AND logic across words. A concatenated
//   keyword like 'Firewall IPS IDS WAF DDoS VPN EDR SIEM' would require
//   all 8 words in one CVE description → returns ~0 results. Per-vendor
//   query (e.g. 'F5', 'Fortinet') returns all CVEs mentioning that vendor;
//   AI Agent downstream filters by product/version.
// - OpenCVE pagination runs only in backfill mode and only if $env.OPENCVE_BEARER is set.
//
// n8n task-runner sandbox notes (v2.16.0+):
//   - `URL` / `URLSearchParams` globals are NOT exposed → manual query string.
//   - `process` global is NOT exposed → use $env helper for env vars.
// ============================================================

const state = $('Code - Backfill State').first().json;
const isBackfill = state.mode === 'backfill';

// Derive per-vendor keywords from D1 solutions list.
const solutionsResp = $('HTTP - GET D1 Solutions').first().json;
const solutions = (solutionsResp && solutionsResp.data) ? solutionsResp.data : [];
const uniqueVendors = Array.from(new Set(solutions.map((s) => (s.vendor || '').trim()).filter(Boolean)));

if (uniqueVendors.length === 0) {
  console.log('[crawler] No vendors in D1 solutions, skipping NVD crawl');
  return [];
}

const out = [];
const nowMs = Date.now();
const DAY_MS = 86400000;
const WINDOW_DAYS = 120;
const TOTAL_DAYS = isBackfill ? (state.backfillDays ?? 365) : 1;

const buildQuery = (params) => {
  const pairs = [];
  for (const [k, v] of Object.entries(params)) {
    pairs.push(encodeURIComponent(k) + '=' + encodeURIComponent(String(v)));
  }
  return pairs.join('&');
};

// Build date windows (oldest → newest).
const nvdWindows = [];
if (isBackfill) {
  for (let offsetDays = TOTAL_DAYS; offsetDays > 0; offsetDays -= WINDOW_DAYS) {
    const end = new Date(nowMs - (offsetDays - WINDOW_DAYS) * DAY_MS);
    const start = new Date(nowMs - offsetDays * DAY_MS);
    const realEnd = end.getTime() > nowMs ? new Date(nowMs) : end;
    nvdWindows.push({
      pubStartDate: start.toISOString().split('.')[0] + '.000',
      pubEndDate: realEnd.toISOString().split('.')[0] + '.999'
    });
  }
} else {
  nvdWindows.push({
    pubStartDate: state.nvdPubStart,
    pubEndDate: state.nvdPubEnd
  });
}

console.log('[crawler] mode=' + state.mode + ' vendors=' + uniqueVendors.length + ' windows=' + nvdWindows.length);

// Per-vendor × per-window NVD search.
for (const vendor of uniqueVendors) {
  for (const w of nvdWindows) {
    const qs = buildQuery({
      keywordSearch: vendor,
      pubStartDate: w.pubStartDate,
      pubEndDate: w.pubEndDate,
      resultsPerPage: '2000'
    });
    const urlString = 'https://services.nvd.nist.gov/rest/json/cves/2.0?' + qs;
    try {
      const res = await fetch(urlString, { method: 'GET' });
      if (!res.ok) {
        console.log('[crawler] NVD query failed', vendor, w.pubStartDate, res.status);
        continue;
      }
      const body = await res.json();
      const hit = (body.vulnerabilities || []).length;
      console.log('[crawler] NVD ' + vendor + ' ' + w.pubStartDate.slice(0,10) + ' → ' + hit + ' CVEs');
      out.push({ json: { source: 'NVD', ...body } });
    } catch (e) {
      console.log('[crawler] NVD error', vendor, w.pubStartDate, String(e));
    }
    // NVD rate limit: 5 req/30s without key. Small sleep to be safe.
    await new Promise((r) => setTimeout(r, 6500));
  }
}

// OpenCVE pagination (backfill only)
// n8n task-runner sandbox blocks `process` — use $env helper instead.
// If $env is also restricted, skip OpenCVE gracefully (NVD already covers 1 year).
let opencveBearer = null;
try {
  if (typeof $env !== 'undefined' && $env && $env.OPENCVE_BEARER) {
    opencveBearer = $env.OPENCVE_BEARER;
  }
} catch (e) {
  console.log('[backfill] $env not accessible:', String(e));
}
if (opencveBearer) {
  const MAX_PAGES = 50;
  for (let page = 1; page <= MAX_PAGES; page++) {
    try {
      const res = await fetch('https://app.opencve.io/api/cve?page=' + page, {
        method: 'GET',
        headers: { 'Authorization': opencveBearer }
      });
      if (!res.ok) {
        console.log('[backfill] OpenCVE page failed', page, res.status);
        break;
      }
      const body = await res.json();
      out.push({ json: { source: 'OpenCVE', ...body } });
      if (!body.results || body.results.length === 0) break;
      if (!body.next) break;
      // Stop if this page's oldest item is already older than TOTAL_DAYS.
      const tail = body.results[body.results.length - 1];
      const ref = tail.updated_at || tail.created_at;
      if (ref) {
        const refMs = Date.parse(ref);
        if (Number.isFinite(refMs) && (nowMs - refMs) > TOTAL_DAYS * DAY_MS) break;
      }
    } catch (e) {
      console.log('[backfill] OpenCVE error page', page, String(e));
      break;
    }
    await new Promise((r) => setTimeout(r, 500));
  }
} else {
  console.log('[backfill] OPENCVE_BEARER not available via $env — skipping OpenCVE backfill (NVD covers 1y)');
}

return out;

// ============================================================
// v2.3 Parse & Structure for D1 Matching
// - Same parser logic as v2.2 for KrCERT / NVD / CISA / OpenCVE.
// - In backfill mode, the 24h OpenCVE recency filter is bypassed.
// - Output item shape identical to v2.2 so AI Agent prompt stays stable.
// ============================================================

const state = $('Code - Backfill State').first().json;
const isBackfill = state.mode === 'backfill';
const today = new Date().toISOString().split('T')[0];
const DAY_MS = 86400000;
const nowMs = Date.now();
const vulnerabilities = [];

for (const item of $input.all()) {
  const source = item.json.source;

  if (source === 'NVD') {
    const vulns = item.json.vulnerabilities || [];
    for (const v of vulns) {
      const cve = v.cve || {};
      const desc = (cve.descriptions || []).find((d) => d.lang === 'en')?.value || '';
      const configs = cve.configurations || [];
      const cpeList = [];
      for (const cfg of configs) {
        for (const node of (cfg.nodes || [])) {
          for (const cpe of (node.cpeMatch || [])) {
            if (cpe.criteria) cpeList.push(cpe.criteria);
          }
        }
      }
      const severity =
        cve.metrics?.cvssMetricV31?.[0]?.cvssData?.baseSeverity ||
        cve.metrics?.cvssMetricV3?.[0]?.cvssData?.baseSeverity ||
        cve.metrics?.cvssMetricV2?.[0]?.baseSeverity ||
        'N/A';
      vulnerabilities.push({
        source: 'NVD',
        cve_id: cve.id || null,
        title: (cve.id || '') + ': ' + desc.substring(0, 160),
        description: desc.substring(0, 800),
        severity,
        published: (cve.published || today).split('T')[0],
        url: cve.id ? ('https://nvd.nist.gov/vuln/detail/' + cve.id) : null,
        cpe: cpeList.slice(0, 10)
      });
    }
  }

  if (source === 'KrCERT') {
    const xml = item.json.body || '';
    const rssItemRegex = /<item>([\s\S]*?)<\/item>/g;
    let m;
    while ((m = rssItemRegex.exec(xml)) !== null) {
      const chunk = m[1];
      const getTag = (tag) => {
        const re = new RegExp('<' + tag + '>(?:<!\\[CDATA\\[)?([\\s\\S]*?)(?:\\]\\]>)?<\\/' + tag + '>');
        const hit = chunk.match(re);
        return hit ? hit[1].trim() : '';
      };
      const title = getTag('title');
      const link = getTag('link');
      const desc = getTag('description').replace(/<[^>]+>/g, '').trim();
      const pubDate = getTag('pubDate');
      if (title) {
        vulnerabilities.push({
          source: 'KrCERT',
          cve_id: (title.match(/CVE-\d{4}-\d{4,7}/i) || [null])[0],
          title,
          description: desc || title,
          severity: 'N/A',
          published: pubDate || today,
          url: link,
          cpe: []
        });
      }
    }
  }

  if (source === 'CISA') {
    const xml = item.json.body || '';
    const itemRegex = /<item>([\s\S]*?)<\/item>/g;
    let m;
    while ((m = itemRegex.exec(xml)) !== null) {
      const chunk = m[1];
      const getTag = (tag) => {
        const re = new RegExp('<' + tag + '>(?:<!\\[CDATA\\[)?([\\s\\S]*?)(?:\\]\\]>)?<\\/' + tag + '>');
        const hit = chunk.match(re);
        return hit ? hit[1].trim() : '';
      };
      const title = getTag('title');
      const link = getTag('link');
      const desc = getTag('description').replace(/<[^>]+>/g, '').substring(0, 600);
      const pubDate = getTag('pubDate');
      if (title) {
        vulnerabilities.push({
          source: 'CISA',
          cve_id: (title.match(/CVE-\d{4}-\d{4,7}/i) || [null])[0],
          title,
          description: desc,
          severity: 'N/A',
          published: pubDate || today,
          url: link,
          cpe: []
        });
      }
    }
  }

  if (source === 'OpenCVE') {
    const results = Array.isArray(item.json.results) ? item.json.results : [];
    for (const r of results) {
      const cveId = r.cve_id || null;
      const desc = (r.description || '').trim();
      const createdAt = r.created_at || null;
      const updatedAt = r.updated_at || null;
      const recencyRef = updatedAt || createdAt;
      if (!isBackfill && recencyRef) {
        const refMs = Date.parse(recencyRef);
        if (Number.isFinite(refMs) && (nowMs - refMs) > DAY_MS) continue;
      }
      vulnerabilities.push({
        source: 'OpenCVE',
        cve_id: cveId,
        title: (cveId || '') + ': ' + desc.substring(0, 160),
        description: desc.substring(0, 800),
        severity: 'N/A',
        published: (createdAt || updatedAt || today).split('T')[0],
        url: cveId ? ('https://app.opencve.io/cve/' + cveId) : null,
        cpe: []
      });
    }
  }
}

return [{ json: {
  date: today,
  mode: state.mode,
  count: vulnerabilities.length,
  hasVulnerabilities: vulnerabilities.length > 0,
  vulnerabilities
}}];

// ============================================================
// v2.4 Combine D1 Solutions + Parsed Vulnerabilities
// v2.3 대비: 솔루션에 cpe_part / aliases / vendor_normalized / product_normalized /
//           cpe_version_range / category 를 동봉하여 다음 노드들이 결정론적으로 매칭/스코어링 가능.
// ============================================================
const parsed = $input.first().json;
const mode = parsed.mode;
const isBackfill = mode === 'backfill';

const solutionsResp = $('HTTP - GET D1 Solutions').first().json;
const allSolutions = (solutionsResp && solutionsResp.data) ? solutionsResp.data : [];

const DEDUP_WINDOW_MS = 24 * 60 * 60 * 1000;
const now = Date.now();

const parseLastMatched = (val) => {
  if (!val) return null;
  const s = String(val);
  const iso = s.includes('T') ? s : s.replace(' ', 'T');
  const withTz = /[zZ]|[+-]\d{2}:?\d{2}$/.test(iso) ? iso : iso + 'Z';
  const ms = Date.parse(withTz);
  return Number.isNaN(ms) ? null : ms;
};

const activeSolutions = [];
const skippedSolutions = [];
for (const s of allSolutions) {
  if (isBackfill) {
    activeSolutions.push(s);
    continue;
  }
  const lastMs = parseLastMatched(s.last_matched_at);
  if (lastMs !== null && (now - lastMs) <= DEDUP_WINDOW_MS) {
    skippedSolutions.push({ id: s.id, vendor: s.vendor, product: s.product, last_matched_at: s.last_matched_at });
  } else {
    activeSolutions.push(s);
  }
}

const parseAliases = (raw) => {
  if (!raw) return [];
  if (Array.isArray(raw)) return raw.filter((x) => typeof x === 'string');
  try {
    const arr = JSON.parse(raw);
    return Array.isArray(arr) ? arr.filter((x) => typeof x === 'string') : [];
  } catch { return []; }
};

return [{ json: {
  date: parsed.date,
  mode,
  backfill_mode: isBackfill,
  hasVulnerabilities: parsed.hasVulnerabilities && activeSolutions.length > 0,
  vulnerabilityCount: parsed.count,
  solutionCount: activeSolutions.length,
  dedupSkippedCount: skippedSolutions.length,
  dedupSkipped: skippedSolutions,
  solutions: activeSolutions.map((s) => ({
    id: s.id,
    vendor: s.vendor,
    product: s.product,
    category: s.category,
    current_version: s.current_version,
    hostname: s.hostname,
    group_company: s.group_company,
    // === v2.4 매칭 메타데이터 ===
    cpe_part: s.cpe_part || null,
    cpe_version_range: s.cpe_version_range || null,
    aliases: parseAliases(s.aliases),
    vendor_normalized: s.vendor_normalized || (s.vendor || '').toLowerCase().replace(/[\s\-_]+/g, ''),
    product_normalized: s.product_normalized || (s.product || '').toLowerCase().replace(/[\s\-_]+/g, ''),
  })),
  vulnerabilities: parsed.vulnerabilities
}}];

// v2.4 AI 응답 파싱 — matches 배열만 사용. teams_report 는 다음 노드가 생성.
const raw = $input.first().json;
const aiText = raw.output || raw.text || (raw.message && raw.message.content) || '';

let parsed = null;
try {
  // 코드블록 fence 제거
  const cleaned = String(aiText).replace(/^```json\s*/i, '').replace(/\s*```$/, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  return [{ json: { matches: [], has_matches: false, parse_error: String(e.message || e), raw_preview: String(aiText).slice(0, 500) } }];
}

const matches = Array.isArray(parsed && parsed.matches) ? parsed.matches : [];
return [{ json: {
  matches,
  has_matches: matches.length > 0,
  parse_error: null
}}];

// ============================================================
// v2.3 Persist Backfill State
// - Runs on every successful execution.
// - On backfill completion: writes `lastBackfillAt` so subsequent runs use daily mode.
// ============================================================
const staticData = $getWorkflowStaticData('global');
const parseAI = $('Code - Parse AI JSON').first().json;

if (parseAI.backfill_mode === true && !staticData.lastBackfillAt) {
  staticData.lastBackfillAt = new Date().toISOString();
}

return $input.all();

// v2.4 Pre-Match Filter — 결정론적 사전 매칭으로 AI 부담 80% 절감.
const combined = $input.first().json;
const solutions = combined.solutions || [];
const vulnerabilities = combined.vulnerabilities || [];

const norm = (s) => String(s || '').toLowerCase().replace(/[\s\-_]+/g, '');
const semverParse = (v) => {
  const m = String(v || '').match(/(\d+)\.(\d+)\.?(\d+)?\.?(\d+)?/);
  return m ? [+m[1], +m[2], +(m[3] || 0), +(m[4] || 0)] : null;
};
const semverCmp = (a, b) => { for (let i = 0; i < 4; i++) if (a[i] !== b[i]) return a[i] - b[i]; return 0; };

function scoreMatch(sol, vuln) {
  const aliases = (sol.aliases || []).map(norm).filter(Boolean);
  const vendorNorm = sol.vendor_normalized || norm(sol.vendor);
  const productNorm = sol.product_normalized || norm(sol.product);

  const haystack = norm(
    (vuln.title || '') + ' ' +
    (vuln.description || '') + ' ' +
    (Array.isArray(vuln.cpe) ? vuln.cpe.join(' ') : (vuln.cpe || ''))
  );

  let score = 0;
  const reasons = [];

  // (a) CPE 정확 매칭 — 가장 강한 신호
  if (sol.cpe_part && Array.isArray(vuln.cpe)) {
    const lo = sol.cpe_part.toLowerCase();
    if (vuln.cpe.some((c) => String(c).toLowerCase().startsWith(lo))) {
      score += 70;
      reasons.push('CPE_EXACT');
    }
  }

  // (b) vendor + product 매칭
  if (vendorNorm && haystack.includes(vendorNorm)) { score += 20; reasons.push('vendor'); }
  if (productNorm && haystack.includes(productNorm)) { score += 20; reasons.push('product'); }

  // (c) alias 매칭 (한↔영, 패밀리 동의어 포함)
  for (const a of aliases) {
    if (a.length >= 3 && haystack.includes(a)) { score += 12; reasons.push('alias:' + a); break; }
  }

  // (d) 버전 범위 매칭
  if (sol.cpe_version_range && sol.current_version) {
    const cur = semverParse(sol.current_version);
    const range = String(sol.cpe_version_range).match(/>=([\d.]+)\s*,\s*<([\d.]+)/);
    if (cur && range) {
      const lo = semverParse(range[1]);
      const hi = semverParse(range[2]);
      if (lo && hi && semverCmp(cur, lo) >= 0 && semverCmp(cur, hi) < 0) {
        score += 30;
        reasons.push('version_in_range');
      }
    }
  }

  return { score, reasons };
}

const candidates = [];
for (const sol of solutions) {
  for (const vuln of vulnerabilities) {
    const { score, reasons } = scoreMatch(sol, vuln);
    if (score >= 35) {
      candidates.push({
        solution_id: sol.id,
        sol_summary: `${sol.vendor} ${sol.product} v${sol.current_version}`,
        vuln_id: vuln.cve_id,
        vuln_summary: vuln.title,
        pre_score: score,
        pre_reasons: reasons,
        solution: sol,
        vulnerability: vuln
      });
    }
  }
}

candidates.sort((a, b) => b.pre_score - a.pre_score);

// 신규 솔루션이 alias/CPE 없이 등록되어 사전필터를 통과하지 못한 경우를 위해
// 의미매칭 노드로 넘길 미커버 쌍도 별도 출력.
const coveredSolIds = new Set(candidates.map((c) => c.solution_id));
const uncoveredSolutions = solutions.filter((s) => !coveredSolIds.has(s.id));

return [{ json: {
  ...combined,
  candidates: candidates.slice(0, 60),
  candidate_count: candidates.length,
  high_confidence_count: candidates.filter((c) => c.pre_score >= 70).length,
  uncovered_solutions: uncoveredSolutions,
  // 의미매칭에 보낼 취약점 페이로드 (상위 50건)
  semantic_payload: {
    vulnerabilities: vulnerabilities.slice(0, 50).map((v) => ({
      cve_id: v.cve_id, title: v.title, description: v.description
    }))
  }
}}];

// EPSS + KEV 조회 → vulnerabilities 에 epss_score / is_kev 부착.
// KEV: 약 1300건 CSV, EPSS: 일별 전체 dump
// 양쪽 모두 무인증, 캐시 가능.
const input = $input.first().json;
const vulns = input.vulnerabilities || [];
const cveIds = vulns.map((v) => v.cve_id).filter(Boolean);

if (cveIds.length === 0) return [{ json: input }];

// === EPSS — 청크당 100개 ===
const epssMap = {};
const CHUNK = 100;
for (let i = 0; i < cveIds.length; i += CHUNK) {
  const slice = cveIds.slice(i, i + CHUNK);
  const url = 'https://api.first.org/data/v1/epss?cve=' + slice.join(',');
  try {
    const r = await this.helpers.httpRequest({ method: 'GET', url, json: true, timeout: 10000 });
    const data = r && r.data ? r.data : [];
    for (const row of data) {
      epssMap[row.cve] = parseFloat(row.epss);
    }
  } catch (e) {
    // ignore — best effort
  }
}

// === CISA KEV ===
const kevSet = new Set();
try {
  const r = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://www.cisa.gov/sites/default/files/feeds/known_exploited_vulnerabilities.json',
    json: true,
    timeout: 15000,
  });
  for (const v of (r && r.vulnerabilities) || []) {
    if (v.cveID) kevSet.add(v.cveID);
  }
} catch (e) {
  // ignore — best effort
}

const enriched = vulns.map((v) => ({
  ...v,
  epss_score: epssMap[v.cve_id] ?? null,
  is_kev: kevSet.has(v.cve_id),
}));

return [{ json: { ...input, vulnerabilities: enriched, epss_kev_enriched: true } }];

// 의미매칭 결과를 candidates 에 보강.
// pre_score 가 35 미만으로 누락된 솔루션×CVE 쌍을 vector similarity 로 다시 끌어옴.
const upstream = $('Code - Pre-Match Filter').first().json;
const semantic = $input.first().json;
const semHits = (semantic && semantic.data) ? semantic.data : [];

const existing = new Set(upstream.candidates.map((c) => c.solution_id + ':' + c.vuln_id));
const solById = Object.fromEntries((upstream.solutions || []).map((s) => [s.id, s]));
const vulnById = Object.fromEntries((upstream.vulnerabilities || []).map((v) => [v.cve_id, v]));

const semanticCandidates = [];
for (const h of semHits) {
  const key = h.solution_id + ':' + h.cve_id;
  if (existing.has(key)) continue;
  const sol = solById[h.solution_id];
  const vuln = vulnById[h.cve_id];
  if (!sol || !vuln) continue;
  semanticCandidates.push({
    solution_id: sol.id,
    sol_summary: `${sol.vendor} ${sol.product} v${sol.current_version}`,
    vuln_id: vuln.cve_id,
    vuln_summary: vuln.title,
    pre_score: Math.round(h.score * 50) + 35,  // 0.7~1.0 → 70~85 정도
    pre_reasons: ['semantic:' + h.score],
    solution: sol,
    vulnerability: vuln
  });
}

const merged = [...upstream.candidates, ...semanticCandidates]
  .sort((a, b) => b.pre_score - a.pre_score)
  .slice(0, 80);

return [{ json: {
  ...upstream,
  candidates: merged,
  candidate_count: merged.length,
  high_confidence_count: merged.filter((c) => c.pre_score >= 70).length,
  semantic_added: semanticCandidates.length
}}];

// v2.4 Format Teams Message — AI 와 분리된 결정론적 포매팅.
// 최대 줄 수 강제 cap + 솔루션별 그룹화 + KEV/EPSS 표시.
const result = $input.first().json;
const matches = result.matches || [];

// 솔루션 정보 lookup (Pre-Match Filter 결과 재사용)
const upstream = $('Code - Merge Semantic Hits').first().json;
const solById = Object.fromEntries((upstream.solutions || []).map((s) => [s.id, s]));
const vulnById = Object.fromEntries((upstream.vulnerabilities || []).map((v) => [v.cve_id, v]));

const date = (result.date || new Date().toISOString().split('T')[0]).slice(0, 10);

if (matches.length === 0) {
  return [{ json: {
    teams_report: `✅ ${date} 매칭된 신규 취약점 없음 (대상 ${upstream.solutionCount || 0}개 솔루션, CVE ${upstream.vulnerabilityCount || 0}건 분석)`,
    line_count: 1,
    total_matches: 0
  }}];
}

const SEV_RANK = { critical: 4, high: 3, medium: 2, low: 1 };
const SEV_EMOJI = { critical: '🔴', high: '🟠', medium: '🟡', low: '🟢' };

// 솔루션별 그룹화
const bySolution = new Map();
for (const m of matches) {
  if (!bySolution.has(m.solution_id)) bySolution.set(m.solution_id, []);
  bySolution.get(m.solution_id).push(m);
}

const lines = [];
let critCount = 0, highCount = 0, kevCount = 0;

for (const [solId, cves] of bySolution.entries()) {
  cves.sort((a, b) => (b.published || '').localeCompare(a.published || ''));
  const top = cves[0];
  const sol = solById[solId] || {};
  const vulnExtra = vulnById[top.cve_id] || {};
  const sev = (top.severity || 'medium').toLowerCase();
  const emoji = SEV_EMOJI[sev] || '⚪';

  if (sev === 'critical') critCount++;
  if (sev === 'high') highCount++;

  const isKev = vulnExtra.is_kev === true;
  const epss = typeof vulnExtra.epss_score === 'number' ? vulnExtra.epss_score : null;
  if (isKev) kevCount++;

  const tags = [];
  if (isKev) tags.push('🔥KEV');
  if (epss != null && epss >= 0.5) tags.push(`EPSS ${epss.toFixed(2)}`);

  const extra = cves.length > 1 ? ` · 외 ${cves.length - 1}건` : '';

  lines.push({
    sev_rank: SEV_RANK[sev] || 0,
    kev_boost: isKev ? 100 : 0,
    line: `${emoji} **${sol.vendor || '?'} ${sol.product || '?'}** v${sol.current_version || '?'} · [${top.cve_id}](${top.url || '#'})${tags.length ? ' · ' + tags.join(' · ') : ''}${extra}`
  });
}

// KEV → 심각도 순 정렬
lines.sort((a, b) => (b.kev_boost - a.kev_boost) || (b.sev_rank - a.sev_rank));

const MAX_LINES = 10;
const truncated = lines.length > MAX_LINES;
const shown = lines.slice(0, MAX_LINES);
const omitted = lines.length - shown.length;

const headerBadges = [];
if (critCount > 0) headerBadges.push(`🔴${critCount}`);
if (highCount > 0) headerBadges.push(`🟠${highCount}`);
if (kevCount > 0) headerBadges.push(`🔥${kevCount}`);

const header = `🛡️ **취약점 매칭** · ${date} · 총 ${matches.length}건 (${headerBadges.join(' ')})`;
const body = shown.map((l) => l.line).join('\n');
const footer = truncated ? `\n_…외 ${omitted}건은 대시보드 확인_` : '';

return [{ json: {
  teams_report: `${header}\n\n${body}${footer}`,
  line_count: shown.length + 2,
  total_matches: matches.length,
  critical_count: critCount,
  high_count: highCount,
  kev_count: kevCount,
  date,
  // matched_vulns POST 용 페이로드 (EPSS/KEV 포함)
  matches_for_d1: matches.map((m) => {
    const vx = vulnById[m.cve_id] || {};
    return {
      solution_id: m.solution_id,
      cve_id: m.cve_id,
      source: m.source || 'AI',
      severity: m.severity || null,
      title: m.title || null,
      description: m.description || null,
      url: m.url || null,
      published: m.published || null,
      first_seen_at: m.published || null,
      match_reasons: m.reason ? [m.reason] : null,
      epss_score: typeof vx.epss_score === 'number' ? vx.epss_score : null,
      is_kev: vx.is_kev === true,
      cvss_score: typeof m.cvss_score === 'number' ? m.cvss_score : null
    };
  })
}}];
